import { ChangeDetectorRef, Component, Inject, OnInit } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Customer } from '../../models/customer';
import { CustomerService } from '../../services/customer.service';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';

@Component({
  selector: 'customer',
  imports: [CommonModule, RouterLink],
  templateUrl: './customer.component.html',
  styleUrls: ['./customer.component.css'],
  standalone: true
})
export class CustomerComponent implements OnInit{
  public customers: Customer[] = [];

  constructor(
    http: HttpClient,
    @Inject('BASE_URL') baseUrl: string,
    private customerService: CustomerService,
    private changeDetectorRef: ChangeDetectorRef,
    private router: Router
  ) {

    const customersEndPoint = baseUrl + 'api/customer/all';
    console.log("End point :" + customersEndPoint);    
  }

  ngOnInit(): void {
    this.loadTransactions();
  }

  loadTransactions() {
    this.customerService.getAll()
      .subscribe((data) => {
        this.customers = data;
        console.log('list...items:' + this.customers.length);

        this.changeDetectorRef.detectChanges();
      });
  }

  viewDetails(id: number) {
    this.router.navigate(['/customer-form/' + id])
  }

  incomeSummary(): number {
    return 0;
  }

  expenseSummary(): number {
    return 0;
  }

  filterBy(filterBy: string) {
  }



}
<div class="row mb-4 g-4">
  <div class="col-md-4 ">
    <div (click)="filterBy('income')" class="card h-100 bg-success bg-opacity-75 text-white">
      <div class="card-body">
        <h5 class="card-title">Income</h5>
        <h3 class="card-title">{{incomeSummary() | currency:'R'}}</h3>
      </div>
    </div>
  </div>
  <div class="col-md-4 ">
    <div (click)="filterBy('expense')" class="card h-100 bg-danger bg-opacity-75 text-white">
      <div class="card-body">
        <h5 class="card-title">Expenses</h5>
        <h3 class="card-title">{{expenseSummary() | currency:'R'}}</h3>
      </div>
    </div>
  </div>
</div>

<h1 id="tableLabel">Customers</h1>

<p *ngIf="!customers?.length"><em>Loading...</em></p>

<div class="ms-auto">
  <a class="btn btn-outline-dark me-2"
     [routerLink]="['/customer-form']">
    <li class="bi bi-plus-circle"> Add New</li>
  </a>

  <div id="filter-caption" style="display:none">Filtered by</div>
</div>

<table class="table table-striped py-2 table-hover align-middle" *ngIf="customers.length">
  <thead>
    <tr>
      <th scope="col">Id</th>
      <th scope="col">Name</th>
      <th scope="col">Number</th>
    </tr>
  </thead>
  <tbody>
    <tr *ngFor="let cust of customers"
        class="trans-row"
        (click)="viewDetails(cust.id)">
      <td>{{ cust.id }}</td>
      <td>{{ cust.name }}</td>
      <td>{{ cust.number }}</td>
    </tr>
  </tbody>
</table>
